public class Person
{
    public string FirstName { get; set; }
    public string LastName { get; set; }

    public Person(string firstName, string lastName)
    {
        FirstName = firstName;
        LastName = lastName;
    }
}

public static class Helpers
{
    public static string GetUpperName(Person person)
    {
        return $"{person.FirstName} {person.LastName}".ToUpperInvariant();
    }
}

